import { generateText } from 'ai';

export async function askWithRetry(model, prompt, maxAttempts = 3) {
  let lastErr;
  for (let i = 0; i < maxAttempts; i++) {
    try {
      return await generateText({ model, prompt });
    } catch (e) {
      if (e?.isRetryable) { lastErr = e; continue; }
      throw e;
    }
  }
  throw lastErr;
}
